section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/personas.json",
  "title": "Personas",
  "type": "object",
  "required": [
    "artefact_id",
    "data_sources",
    "archetypes",
    "primary_persona",
    "validation_status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "data_sources": {
      "type": "array",
      "description": "interviews / surveys / analytics / tickets",
      "minItems": 1
    },
    "archetypes": {
      "type": "array",
      "description": "3-5 personas {name, goals, behaviours, frustrations, context}",
      "minItems": 1
    },
    "primary_persona": {
      "type": "string",
      "description": "single referenced archetype for the next cycle",
      "minLength": 1
    },
    "validation_status": {
      "type": "object",
      "description": "method + sign-off"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "personas-2026-05-23",
  "data_sources": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "archetypes": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "primary_persona": "draft",
  "validation_status": {
    "key": "value"
  },
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
